export type TocItem = {
    title: string;
    path: string;
    contents: TocItem[];
    href: string;
};
export type Manifest = {
    filename: string;
    nav?: {
        toc: TocItem[];
    };
    title: string;
    renditionLayout: `reflowable` | `pre-paginated` | undefined;
    renditionFlow?: `scrolled-continuous` | `scrolled-doc` | `paginated` | `auto`;
    renditionSpread: `none` | `landscape` | `portrait` | `both` | `auto` | undefined;
    readingDirection: "ltr" | "rtl";
    guide?: {
        type: `cover` | `title-page` | `copyright-page` | `text`;
        title: string;
        href: string;
    }[];
    spineItems: {
        id: string;
        index: number;
        href: string;
        renditionLayout?: `reflowable` | `pre-paginated`;
        progressionWeight?: number;
        pageSpreadLeft?: true | undefined;
        pageSpreadRight?: true | undefined;
        mediaType?: string;
    }[];
    items: {
        id: string;
        href: string;
        mediaType?: string;
    }[];
};
